"use client";

/* ════════════════════════════════════════════════════════════════════════
   Study · Record — the parchment decision ledger (study spec §4.5).
   Split shell: navy "Magellan triages" companion (left, foldable + resizable)
   + parchment Record room (right) — a decision inbox of white dept-striped
   cards with Waiting/Done tabs. "Ask Magellan" on any card unfolds the
   companion, re-scopes its header, marks the card discussing, and appends the
   item's question + Magellan's answer to the thread. Ported from
   magellan-study-5-record.html. Currency = USD ($).
   ════════════════════════════════════════════════════════════════════════ */

import { useEffect, useRef, useState } from "react";
import { useRouter } from "next/navigation";
import "./StudyRecord.css";

const RAIL_W = 96;

type AskKey = "hydrangea" | "vaseads" | "twopos" | "vipsunset" | "welcome" | "freeship";

/* The six explain entries — scope/q/a ported verbatim from the template's
   `explain` object. Answer HTML keeps the inline <b>/<span class="good">. */
const EXPLAIN: Record<AskKey, { scope: string; q: string; a: string }> = {
  hydrangea: {
    scope: "Hydrangea reorder",
    q: "Why is this the urgent one?",
    a: 'You&rsquo;re at <b>40 stems</b>, burning ~13/day — but the next 14 days include three weekend weddings that lean on hydrangea, pushing it to ~16/day. At that rate you&rsquo;re dry by Friday, and Kunming freight is 4 days door-to-cold-storage, so a PO today lands Thursday with a half-day buffer. Wait one more day and you&rsquo;re betting the weddings against a stockout — and a missed wedding order costs far more than the $38K headline. Want the math on the wedding load?',
  },
  vaseads: {
    scope: "Cylinder Vase ads",
    q: "Walk me through the vase ads.",
    a: 'It&rsquo;s spending <b>$800/day</b> sending paid clicks to a product out of stock since Tuesday — 21 units of demand last week, all bounced. Pausing stops the bleed now; the vases land in ~2 days on PO #4131. I can set it to <span class="good">auto-resume on restock</span> so you don&rsquo;t have to remember — want me to?',
  },
  twopos: {
    scope: "PO approvals",
    q: "Why do these need me?",
    a: 'They&rsquo;re routine restocks, not judgment calls — that&rsquo;s why they&rsquo;re grouped. Kunming $48K is your standard weekly mix plus 10% safety stock for the wedding load; Belgian Cocoa $22K refills chocolate, now at 9 days of cover against a 14-day reorder point. Both quantities come from the 14-day forecast. They only wait on you because $70K crosses your auto-approve ceiling — approve and they send tonight.',
  },
  vipsunset: {
    scope: "VIP sunset",
    q: "Talk me through the VIP sunset.",
    a: 'The 247 haven&rsquo;t opened in 180 days, and Klaviyo reads continued sends to dead contacts as low engagement — which quietly drags inbox placement for your <b>2,600 active</b> subscribers too. Sunsetting protects deliverability for the people who do open. It isn&rsquo;t deletion — they&rsquo;re suppressed, so if one re-engages they come back automatically. Fully reversible.',
  },
  welcome: {
    scope: "Welcome flow v2",
    q: "Tell me about the welcome flow.",
    a: "This is the v2 sitting in your Library. The current flow&rsquo;s open rate slipped 8% on a stale subject line; the new version leads with the craft story instead of a discount and tested better against your brand. Shipping swaps the live sequence — anyone mid-flow finishes on the old one to avoid double-sends. Low risk, reversible. Want to preview it first?",
  },
  freeship: {
    scope: "Free-ship threshold",
    q: "What&rsquo;s the shipping issue?",
    a: 'Right now anything under $1,200 ships free, but after Lalamove last-mile, orders between <b>$800&ndash;1,200 lose money</b> on shipping. Your order distribution says raising the floor to $1,500 nudges ~18% of those to add an item to qualify and lets the rest pay shipping — margin improves without denting AOV. I&rsquo;ve modeled three thresholds; want them side by side?',
  },
};

type Msg = { role: "you" | "mag"; html: string; t?: string };

export function StudyRecord() {
  const router = useRouter();
  const [folded, setFolded] = useState(false);
  const [convoW, setConvoW] = useState(400);
  const [dragging, setDragging] = useState(false);
  const [tab, setTab] = useState<"waiting" | "done">("waiting");
  const [scope, setScope] = useState<{ label: string; compass: boolean }>({ label: "Record · 12 waiting", compass: false });
  const [discussing, setDiscussing] = useState<AskKey | null>(null);
  const [msgs, setMsgs] = useState<Msg[]>([
    { role: "you", html: "What should I handle first?", t: "9:04" },
    {
      role: "mag",
      t: "9:04",
      html:
        'Of the 12 waiting, three are time-sensitive — but only one actually <b>costs you money to ignore</b>: the Kunming hydrangea reorder. <span class="alert">$38K/week if it stocks out</span>, and that&rsquo;s in 3 days. The other two can sit until tomorrow with no cost.<br><br>The rest are routine. Want me to send the two standard reorder POs and leave the judgment calls for you?',
    },
  ]);

  const bodyRef = useRef<HTMLDivElement>(null);

  const clamp = (v: number) => {
    const max = Math.min(typeof window !== "undefined" ? window.innerWidth * 0.55 : 640, 640);
    return Math.max(320, Math.min(max, v));
  };

  // Keep the companion scrolled to the newest message (matches template).
  useEffect(() => {
    const b = bodyRef.current;
    if (b) b.scrollTop = b.scrollHeight;
  }, [msgs, folded]);

  const ask = (key: AskKey) => {
    const ex = EXPLAIN[key];
    setFolded(false);
    setDiscussing(key);
    setScope({ label: ex.scope, compass: true });
    const now = new Date().toLocaleTimeString([], { hour: "2-digit", minute: "2-digit", hour12: false });
    setMsgs((m) => [
      ...m,
      { role: "you", html: ex.q, t: now },
      { role: "mag", html: ex.a, t: now },
    ]);
  };

  return (
    <div
      className={`study-record${folded ? " folded" : ""}`}
      style={{ ["--convo-w" as string]: `${convoW}px` } as React.CSSProperties}
    >
      {/* ── LEFT — Magellan triages ── */}
      <aside className="convo">
        <div className="convo-head">
          <div className="ch-avatar">M</div>
          <div className="ch-id">
            <div className="ch-name">Magellan</div>
            <div className="ch-scope">
              <span className={`dot${scope.compass ? " compass" : ""}`} />
              {scope.label}
            </div>
          </div>
          <button className="ch-fold" title="See the full list" type="button" onClick={() => setFolded(true)}>
            <svg viewBox="0 0 24 24" fill="none" stroke="currentColor"><polyline points="15 18 9 12 15 6" /></svg>
          </button>
        </div>

        <div className="convo-body" ref={bodyRef}>
          <div className="day">Today · 9:04 AM</div>
          {msgs.map((m, i) =>
            m.role === "you" ? (
              <div key={i} className="msg-you">
                <span dangerouslySetInnerHTML={{ __html: m.html }} />
                {m.t && <span className="t">{m.t}</span>}
              </div>
            ) : (
              <div key={i} className="msg-mag">
                <div className="who">Magellan{m.t ? ` · ${m.t}` : ""}</div>
                <div className="body">
                  <span dangerouslySetInnerHTML={{ __html: m.html }} />
                  {/* Seeded opening exchange carries the two triage actions. */}
                  {i === 1 && (
                    <div className="mag-actions">
                      <button className="mag-act primary" type="button">Send the 2 routine POs</button>
                      <button className="mag-act" type="button">Show me everything</button>
                    </div>
                  )}
                </div>
              </div>
            )
          )}
        </div>

        <div className="convo-composer">
          <div className="cc-foot"><span className="dot" />Scoped to Record</div>
          <div className="cc-wrap">
            <input className="cc-input" placeholder="Tell Magellan how to handle these…" />
            <div className="cc-row">
              <button className="cc-btn" title="Attach" type="button">
                <svg viewBox="0 0 24 24" fill="none" stroke="currentColor"><path d="M21.44 11.05l-9.19 9.19a6 6 0 01-8.49-8.49l9.19-9.19a4 4 0 015.66 5.66l-9.2 9.19a2 2 0 01-2.83-2.83l8.49-8.48" /></svg>
              </button>
              <span className="cc-spacer" />
              <button className="cc-mic" title="Hold to talk" type="button">
                <svg viewBox="0 0 24 24" fill="none" stroke="currentColor"><path d="M12 1a3 3 0 00-3 3v8a3 3 0 006 0V4a3 3 0 00-3-3z" /><path d="M19 10v2a7 7 0 01-14 0v-2" /><line x1="12" y1="19" x2="12" y2="23" /><line x1="8" y1="23" x2="16" y2="23" /></svg>
              </button>
              <button className="cc-send" title="Send" type="button">
                <svg viewBox="0 0 24 24" fill="none" stroke="currentColor"><line x1="12" y1="19" x2="12" y2="5" /><polyline points="5 12 12 5 19 12" /></svg>
              </button>
            </div>
          </div>
        </div>
      </aside>

      {/* resizer */}
      <div
        className={`resizer${dragging ? " dragging" : ""}`}
        title="Drag to resize · double-click to reset"
        onPointerDown={(e) => { setDragging(true); e.currentTarget.setPointerCapture(e.pointerId); }}
        onPointerMove={(e) => { if (dragging) setConvoW(clamp(e.clientX - RAIL_W)); }}
        onPointerUp={(e) => { setDragging(false); e.currentTarget.releasePointerCapture(e.pointerId); }}
        onDoubleClick={() => setConvoW(400)}
      >
        <div className="resizer-grip" />
      </div>

      {/* sliver to bring the companion back */}
      <button className="unfold" title="Show Magellan" type="button" onClick={() => setFolded(false)}>
        <svg viewBox="0 0 24 24" fill="none" stroke="currentColor"><polyline points="9 18 15 12 9 6" /></svg>
      </button>

      {/* ── RIGHT — Record ── */}
      <main className="work">
        <div className="rec-head">
          <div className="rh-title">Record</div>
          <div className="rh-sub">What&rsquo;s waiting on your decision. What&rsquo;s already been done.</div>
          <div className="rh-stat"><span className="pulse" />3 urgent<span className="sep" />12 waiting<span className="sep" /><b>$38K/wk at stake</b></div>
          <div className="rec-tabs">
            <button className={`rec-tab${tab === "waiting" ? " active" : ""}`} type="button" onClick={() => setTab("waiting")}>
              <span>Waiting</span><span className="ct">12</span>
            </button>
            <button className={`rec-tab${tab === "done" ? " active" : ""}`} type="button" onClick={() => setTab("done")}>
              <span>Done</span><span className="ct">147</span>
            </button>
          </div>
        </div>

        <div className="rec-body">

          {/* WAITING */}
          <div className={`rec-panel${tab === "waiting" ? " active" : ""}`}>

            <div className="sec urgent first"><span className="pulse" />Needs you now<span className="meta"><b>3 urgent</b> · $38K/wk at stake</span></div>
            <div className="rlist">

              <div className={`rec-card ops urgent${discussing === "hydrangea" ? " discussing" : ""}`}>
                <div className="rc-top"><span className="rc-dept">Operations</span><span className="rc-age">flagged 6h ago</span><span className="rc-stake">$38K/wk at stake</span></div>
                <div className="rc-title">Reorder hydrangeas from Kunming — stockout in 3 days</div>
                <div className="rc-body">Down to <b>40 stems</b> at current velocity. Kunming air freight + cold storage runs <b>4 days</b>, so a PO has to go today to avoid a gap during the weekend wedding orders.</div>
                <div className="rc-src">From inventory monitor · cross-checked against next 14 days of orders</div>
                <div className="rc-actions">
                  <button className="btn-do" type="button">Send PO to Kunming<svg viewBox="0 0 24 24" fill="none" stroke="currentColor"><line x1="5" y1="12" x2="19" y2="12" /><polyline points="12 5 19 12 12 19" /></svg></button>
                  <button className="btn-quiet" type="button">Snooze</button>
                  <button className="btn-quiet ghost" type="button">Dismiss</button>
                  <span className="rc-spacer" />
                  <button className="btn-ask" type="button" onClick={() => ask("hydrangea")}><svg viewBox="0 0 24 24" fill="none" stroke="currentColor"><path d="M21 11.5a8.38 8.38 0 0 1-.9 3.8 8.5 8.5 0 0 1-7.6 4.7 8.38 8.38 0 0 1-3.8-.9L3 21l1.9-5.7a8.38 8.38 0 0 1-.9-3.8 8.5 8.5 0 0 1 4.7-7.6 8.38 8.38 0 0 1 3.8-.9h.5a8.48 8.48 0 0 1 8 8v.5z" /></svg>Ask Magellan</button>
                </div>
              </div>

              <div className={`rec-card growth urgent${discussing === "vaseads" ? " discussing" : ""}`}>
                <div className="rc-top"><span className="rc-dept">Growth</span><span className="rc-age">5h ago</span><span className="rc-stake">$800/day wasted</span></div>
                <div className="rc-title">Pause Cylinder Vase Meta ads — product is out of stock</div>
                <div className="rc-body">Spending <b>$800/day</b> driving traffic to a product with zero inventory. 21 units of demand in the last 7 days with nothing to sell — every click is paid for and lost.</div>
                <div className="rc-src">From ad spend monitor · seen 2:14 PM</div>
                <div className="rc-actions">
                  <button className="btn-do" type="button">Pause campaign<svg viewBox="0 0 24 24" fill="none" stroke="currentColor"><line x1="5" y1="12" x2="19" y2="12" /><polyline points="12 5 19 12 12 19" /></svg></button>
                  <button className="btn-quiet" type="button">Snooze</button>
                  <button className="btn-quiet ghost" type="button">Dismiss</button>
                  <span className="rc-spacer" />
                  <button className="btn-ask" type="button" onClick={() => ask("vaseads")}><svg viewBox="0 0 24 24" fill="none" stroke="currentColor"><path d="M21 11.5a8.38 8.38 0 0 1-.9 3.8 8.5 8.5 0 0 1-7.6 4.7 8.38 8.38 0 0 1-3.8-.9L3 21l1.9-5.7a8.38 8.38 0 0 1-.9-3.8 8.5 8.5 0 0 1 4.7-7.6 8.38 8.38 0 0 1 3.8-.9h.5a8.48 8.48 0 0 1 8 8v.5z" /></svg>Ask Magellan</button>
                </div>
              </div>

              <div className={`rec-card ops urgent${discussing === "twopos" ? " discussing" : ""}`}>
                <div className="rc-top"><span className="rc-dept">Operations</span><span className="rc-age">3h ago</span><span className="rc-stake">2 POs · $70K</span></div>
                <div className="rc-title">Two purchase orders need your sign-off before they send</div>
                <div className="rc-body">Kunming Flowers <b>$48K</b> and Belgian Cocoa <b>$22K</b>. Quantities come from your 14-day demand forecast plus safety stock — drafted and ready, just need approval to go to suppliers.</div>
                <div className="rc-actions">
                  <button className="btn-do" type="button">Approve &amp; send<svg viewBox="0 0 24 24" fill="none" stroke="currentColor"><line x1="5" y1="12" x2="19" y2="12" /><polyline points="12 5 19 12 12 19" /></svg></button>
                  <button className="btn-quiet" type="button">Review first</button>
                  <button className="btn-quiet ghost" type="button">Snooze</button>
                  <span className="rc-spacer" />
                  <button className="btn-ask" type="button" onClick={() => ask("twopos")}><svg viewBox="0 0 24 24" fill="none" stroke="currentColor"><path d="M21 11.5a8.38 8.38 0 0 1-.9 3.8 8.5 8.5 0 0 1-7.6 4.7 8.38 8.38 0 0 1-3.8-.9L3 21l1.9-5.7a8.38 8.38 0 0 1-.9-3.8 8.5 8.5 0 0 1 4.7-7.6 8.38 8.38 0 0 1 3.8-.9h.5a8.48 8.48 0 0 1 8 8v.5z" /></svg>Ask Magellan</button>
                </div>
              </div>

            </div>

            <div className="sec">Sitting<span className="meta">9 open · no cost to wait</span><span className="sec-rule" /></div>
            <div className="rlist">

              <div className={`rec-card customers${discussing === "vipsunset" ? " discussing" : ""}`}>
                <div className="rc-top"><span className="rc-dept">Customers</span><span className="rc-age">4 days ago</span><span className="rc-stake">deliverability</span></div>
                <div className="rc-title">Sunset the lapsed VIP segment in Klaviyo</div>
                <div className="rc-body">247 contacts haven&rsquo;t opened in 180 days. Cleaning them improves your sender reputation and inbox placement for everyone else.</div>
                <div className="rc-actions">
                  <button className="btn-do" type="button">Sunset segment<svg viewBox="0 0 24 24" fill="none" stroke="currentColor"><line x1="5" y1="12" x2="19" y2="12" /><polyline points="12 5 19 12 12 19" /></svg></button>
                  <button className="btn-quiet" type="button">Snooze</button>
                  <button className="btn-quiet ghost" type="button">Dismiss</button>
                  <span className="rc-spacer" />
                  <button className="btn-ask" type="button" onClick={() => ask("vipsunset")}><svg viewBox="0 0 24 24" fill="none" stroke="currentColor"><path d="M21 11.5a8.38 8.38 0 0 1-.9 3.8 8.5 8.5 0 0 1-7.6 4.7 8.38 8.38 0 0 1-3.8-.9L3 21l1.9-5.7a8.38 8.38 0 0 1-.9-3.8 8.5 8.5 0 0 1 4.7-7.6 8.38 8.38 0 0 1 3.8-.9h.5a8.48 8.48 0 0 1 8 8v.5z" /></svg>Ask Magellan</button>
                </div>
              </div>

              <div className={`rec-card growth${discussing === "welcome" ? " discussing" : ""}`}>
                <div className="rc-top"><span className="rc-dept">Growth</span><span className="rc-age">2 days ago</span><span className="rc-stake">+8% open est.</span></div>
                <div className="rc-title">Ship Welcome flow v2 — replaces the current sequence</div>
                <div className="rc-body">The refreshed welcome flow is <b>ready in your Library</b>. Magellan estimates +8% open rate from the new subject line. Swapping it in is one click.</div>
                <div className="rc-src">From Library · &ldquo;Welcome flow open rate dropped 8%&rdquo;</div>
                <div className="rc-actions">
                  <button className="btn-do" type="button">Approve &amp; ship<svg viewBox="0 0 24 24" fill="none" stroke="currentColor"><line x1="5" y1="12" x2="19" y2="12" /><polyline points="12 5 19 12 12 19" /></svg></button>
                  <button className="btn-quiet" type="button" onClick={() => router.push("/study/library")}>Open in Library</button>
                  <button className="btn-quiet ghost" type="button">Snooze</button>
                  <span className="rc-spacer" />
                  <button className="btn-ask" type="button" onClick={() => ask("welcome")}><svg viewBox="0 0 24 24" fill="none" stroke="currentColor"><path d="M21 11.5a8.38 8.38 0 0 1-.9 3.8 8.5 8.5 0 0 1-7.6 4.7 8.38 8.38 0 0 1-3.8-.9L3 21l1.9-5.7a8.38 8.38 0 0 1-.9-3.8 8.5 8.5 0 0 1 4.7-7.6 8.38 8.38 0 0 1 3.8-.9h.5a8.48 8.48 0 0 1 8 8v.5z" /></svg>Ask Magellan</button>
                </div>
              </div>

              <div className={`rec-card finance${discussing === "freeship" ? " discussing" : ""}`}>
                <div className="rc-top"><span className="rc-dept">Finance</span><span className="rc-age">6 days ago</span><span className="rc-stake">margin</span></div>
                <div className="rc-title">Review the free-shipping threshold</div>
                <div className="rc-body">Small orders under $1,200 are shipping at a loss after last-mile cost. Raising the free-ship floor to $1,500 protects margin without hurting AOV, based on your order distribution.</div>
                <div className="rc-actions">
                  <button className="btn-do" type="button">See the analysis<svg viewBox="0 0 24 24" fill="none" stroke="currentColor"><line x1="5" y1="12" x2="19" y2="12" /><polyline points="12 5 19 12 12 19" /></svg></button>
                  <button className="btn-quiet" type="button">Snooze</button>
                  <button className="btn-quiet ghost" type="button">Dismiss</button>
                  <span className="rc-spacer" />
                  <button className="btn-ask" type="button" onClick={() => ask("freeship")}><svg viewBox="0 0 24 24" fill="none" stroke="currentColor"><path d="M21 11.5a8.38 8.38 0 0 1-.9 3.8 8.5 8.5 0 0 1-7.6 4.7 8.38 8.38 0 0 1-3.8-.9L3 21l1.9-5.7a8.38 8.38 0 0 1-.9-3.8 8.5 8.5 0 0 1 4.7-7.6 8.38 8.38 0 0 1 3.8-.9h.5a8.48 8.48 0 0 1 8 8v.5z" /></svg>Ask Magellan</button>
                </div>
              </div>

            </div>
          </div>

          {/* DONE — the audit trail */}
          <div className={`rec-panel${tab === "done" ? " active" : ""}`}>
            <div className="sec first">Last 24 hours<span className="meta">reversible</span><span className="sec-rule" /></div>
            <div className="done-list" style={{ marginBottom: 30 }}>
              <div className="done-row">
                <span className="dr-dept" style={{ ["--dept" as string]: "var(--d-growth)" } as React.CSSProperties} />
                <div className="dr-main">
                  <div className="dr-what">Refreshed the welcome-flow subject line</div>
                  <div className="dr-sub"><span className="who">You</span><span className="sep" />2 hours ago<span className="sep" />from &ldquo;Welcome flow&rdquo; thread</div>
                </div>
                <button className="dr-undo" type="button">Undo <span className="win">· 22h left</span></button>
              </div>
              <div className="done-row">
                <span className="dr-dept" style={{ ["--dept" as string]: "var(--d-ops)" } as React.CSSProperties} />
                <div className="dr-main">
                  <div className="dr-what">Sent PO #4131 to Kunming — ceramic vases</div>
                  <div className="dr-sub"><span className="who">Magellan · auto</span><span className="sep" />this morning<span className="sep" /><span className="res">PO confirmed</span></div>
                </div>
                <button className="dr-undo" type="button">Undo <span className="win">· 19h left</span></button>
              </div>
              <div className="done-row">
                <span className="dr-dept" style={{ ["--dept" as string]: "var(--d-growth)" } as React.CSSProperties} />
                <div className="dr-main">
                  <div className="dr-what">Paused 2 fatigued Meta campaigns</div>
                  <div className="dr-sub"><span className="who">You</span><span className="sep" />yesterday 4:40 PM<span className="sep" /><span className="res">saving $1,400/day</span></div>
                </div>
                <button className="dr-undo" type="button">Undo <span className="win">· 6h left</span></button>
              </div>
            </div>

            <div className="sec">Earlier<span className="meta">locked</span><span className="sec-rule" /></div>
            <div className="done-list">
              <div className="done-row">
                <span className="dr-dept" style={{ ["--dept" as string]: "var(--d-customers)" } as React.CSSProperties} />
                <div className="dr-main">
                  <div className="dr-what">Sent Valentine&rsquo;s reactivation to lapsed VIPs</div>
                  <div className="dr-sub"><span className="who">You</span><span className="sep" />Feb 12<span className="sep" /><span className="res">34% open · $42K</span></div>
                </div>
                <span className="dr-locked">Sent</span>
              </div>
              <div className="done-row">
                <span className="dr-dept" style={{ ["--dept" as string]: "var(--d-ops)" } as React.CSSProperties} />
                <div className="dr-main">
                  <div className="dr-what">Reordered hydrangeas from Kunming</div>
                  <div className="dr-sub"><span className="who">Magellan · auto</span><span className="sep" />Feb 8<span className="sep" /><span className="res">no stockout</span></div>
                </div>
                <span className="dr-locked">Done</span>
              </div>
              <div className="done-row">
                <span className="dr-dept" style={{ ["--dept" as string]: "var(--d-finance)" } as React.CSSProperties} />
                <div className="dr-main">
                  <div className="dr-what">Updated COGS for the new cake line</div>
                  <div className="dr-sub"><span className="who">You</span><span className="sep" />Feb 5<span className="sep" />4 SKUs</div>
                </div>
                <span className="dr-locked">Done</span>
              </div>
            </div>
          </div>

        </div>
      </main>
    </div>
  );
}
